const url = 'http://127.0.0.1:3000/api/access-token';
const options = {
  method: 'POST',
  headers: {
    Authorization: 'Bearer REPLACE_BEARER_TOKEN',
    'content-type': 'application/json'
  },
  body: '{"name":"string","description":"string","scopes":["string"],"spaceIds":["string"],"baseIds":["string"],"hasFullAccess":true,"expiredTime":"2024-03-25"}'
};

try {
  const response = await fetch(url, options);
  const data = await response.json();
  console.log(data);
} catch (error) {
  console.error(error);
}

const http = require('http');

const options = {
  method: 'POST',
  hostname: '127.0.0.1',
  port: '3000',
  path: '/api/access-token',
  headers: {
    Authorization: 'Bearer REPLACE_BEARER_TOKEN',
    'content-type': 'application/json'
  }
};

const req = http.request(options, function (res) {
  const chunks = [];

  res.on('data', function (chunk) {
    chunks.push(chunk);
  });

  res.on('end', function () {
    const body = Buffer.concat(chunks);
    console.log(body.toString());
  });
});

req.write(JSON.stringify({
  name: 'string',
  description: 'string',
  scopes: ['string'],
  spaceIds: ['string'],
  baseIds: ['string'],
  hasFullAccess: true,
  expiredTime: '2024-03-25'
}));
req.end();

